"use strict";const WEBHOOK_URL="https://hook.eu1.make.com/REPLACE_WITH_YOUR_WEBHOOK_ID";let submitted=!1;async function submitLead(e){const t=await fetch(WEBHOOK_URL,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(e)});if(!t.ok)throw new Error(`HTTP ${t.status}`)}function showFormError(e){const t=document.getElementById("form-error");t&&(t.textContent=e,t.classList.add("visible"))}function clearFormError(){const e=document.getElementById("form-error");e&&(e.textContent="",e.classList.remove("visible"))}function initForm(){const e=document.getElementById("lead-form"),t=document.getElementById("submit-btn"),n=document.getElementById("form-success");e&&e.addEventListener("submit",async e=>{if(e.preventDefault(),submitted)return;clearFormError();const o=document.getElementById("first-name")?.value.trim()||"",r=document.getElementById("email")?.value.trim()||"",i=document.getElementById("gdpr")?.checked;if(!o)return void showFormError("Veuillez entrer votre prénom.");if(!r||!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(r))return void showFormError("Veuillez entrer une adresse e-mail valide.");if(!i)return void showFormError("Vous devez accepter la politique de confidentialité (RGPD) pour continuer.");t.disabled=!0,t.textContent="Envoi en cours…";const s={first_name:o,email:r,statut:sessionStorage.getItem("quiz_statut")||"",volume:sessionStorage.getItem("quiz_volume")||"",connexion:sessionStorage.getItem("quiz_connexion")||"",timestamp:(new Date).toISOString()};try{await submitLead(s),submitted=!0,n&&(n.textContent="✓ Merci ! Votre plan d'action vous a été envoyé par e-mail.",n.classList.add("show")),setTimeout(()=>{window.location.href="index.html"},2500)}catch{t.disabled=!1,t.textContent="Obtenir mon plan d'action (PDF)",showFormError("Une erreur est survenue. Veuillez réessayer dans quelques instants.")}})}function init(){initForm()}document.addEventListener("DOMContentLoaded",init);